<?php
namespace App\Http\Requests\Admin\Content;use App\Domain\Inventory\ItemClassification;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Item;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
class LootEntryRequest extends FormRequest{public function authorize(){return true;}public function rules(){$monster=$this->route('monster');$entry=$this->route('lootEntry');$unique=Rule::unique('monster_loot_entries','item_id')->where(function($query)use($monster){return$query->where('monster_id',$monster->id);});if($entry)$unique->ignore($entry->id);return['item_id'=>['required','integer','exists:items,id',$unique],'drop_chance_basis_points'=>'required|integer|min:0|max:10000','minimum_quantity'=>'required|integer|min:1','maximum_quantity'=>'required|integer|min:1|gte:minimum_quantity','status'=>['required',Rule::in(CatalogStatus::values())],'sort_order'=>'required|integer|min:0'];}public function withValidator($validator){$validator->after(function($validator){if($validator->errors()->has('item_id')||$validator->errors()->has('minimum_quantity')||$validator->errors()->has('maximum_quantity'))return;$item=Item::find($this->input('item_id'));if(!$item)return;try{$kind=app(ItemClassification::class)->classify($item);if($kind===ItemClassification::UNIQUE&&((int)$this->input('minimum_quantity')!==1||(int)$this->input('maximum_quantity')!==1))$validator->errors()->add('maximum_quantity','Los objetos no apilables requieren cantidad mínima y máxima igual a 1.');}catch(\InvalidArgumentException $e){$validator->errors()->add('item_id',$e->getMessage());}});}}
